    36→/**
    37→ * Class representing a configured provider which encapsulates configuration
    38→ * (provider name + optional argument), the provider loading logic, and
    39→ * the loaded Provider object itself.
    40→ *
    41→ * @author  Andreas Sterbenz
    42→ * @since   1.5
    43→ */
    44→final class ProviderConfig {
    45→
    46→    private static final sun.security.util.Debug debug =
    47→        sun.security.util.Debug.getInstance("jca", "ProviderConfig");
    48→
    49→    // suffix for identifying the SunPKCS11-Solaris provider
    50→    private static final String P11_SOL_NAME = "SunPKCS11";
    51→
    52→    // config file argument of the SunPKCS11-Solaris provider
    53→    private static final String P11_SOL_ARG  =
    54→        "${java.home}/conf/security/sunpkcs11-solaris.cfg";
    55→
    56→    // maximum number of times to try loading a provider before giving up
    57→    private static final int MAX_LOAD_TRIES = 30;
    58→
    59→    // could be provider name (module) or provider class name (legacy)
    60→    private final String provName;
    61→
    62→    // argument to the Provider.configure() call, never null
    63→    private final String argument;
    64→
    65→    // number of times we have already tried to load this provider
    66→    private int tries;
    67→
    68→    // Provider object, if loaded
    69→    private volatile Provider provider;
    70→
    71→    // flag indicating if we are currently trying to load the provider
    72→    // used to detect recursion
    73→    private boolean isLoading;
    74→
    75→    ProviderConfig(String provName, String argument) {
    76→        if (provName.endsWith(P11_SOL_NAME) && argument.equals(P11_SOL_ARG)) {
    77→            checkSunPKCS11Solaris();
    78→        }
    79→        this.provName = provName;
    80→        this.argument = expand(argument);
    81→    }
    82→
    83→    ProviderConfig(String provName) {
    84→        this(provName, "");
    85→    }
    86→
    87→    ProviderConfig(Provider provider) {
    88→        this.provName = provider.getName();
    89→        this.argument = "";
    90→        this.provider = provider;
    91→    }
    92→
    93→    // check if we should try to load the SunPKCS11-Solaris provider
    94→    // avoid if not available (pre Solaris 10) to reduce startup time
    95→    // or if disabled via system property
    96→    private void checkSunPKCS11Solaris() {
    97→        File file = new File("/usr/lib/libpkcs11.so");
    98→        if (file.exists() == false ||
    99→            ("false".equalsIgnoreCase(System.getProperty
   100→                ("sun.security.pkcs11.enable-solaris")))) {
   101→             tries = MAX_LOAD_TRIES;
   102→        }
   103→    }
   104→
   105→    private boolean hasArgument() {
   106→        return !argument.isEmpty();
   107→    }
   108→
   109→    // should we try to load this provider?
   110→    private boolean shouldLoad() {
   111→        return (tries < MAX_LOAD_TRIES);
   112→    }
   113→
   114→    // do not try to load this provider again
   115→    private void disableLoad() {
   116→        tries = MAX_LOAD_TRIES;
   117→    }
   118→
   119→    boolean isLoaded() {
   120→        return (provider != null);
   121→    }
   122→
   123→    @Override
   124→    public boolean equals(Object obj) {
   125→        if (this == obj) {
   126→            return true;
   127→        }
   128→        if (!(obj instanceof ProviderConfig other)) {
   129→            return false;
   130→        }
   131→        return this.provName.equals(other.provName)
   132→            && this.argument.equals(other.argument);
   133→
   134→    }
   135→
   136→    @Override
   137→    public int hashCode() {
   138→        return Objects.hash(provName, argument);
   139→    }
   140→
   141→    public String toString() {
   142→        if (hasArgument()) {
   143→            return provName + "('" + argument + "')";
   144→        } else {
   145→            return provName;
   146→        }
   147→    }
   148→
   149→    /**
   150→     * Get the provider object. Loads the provider if it is not already loaded.
   151→     */
   152→    Provider getProvider() {
   153→        // volatile variable load
   154→        Provider p = provider;
   155→        if (p != null) {
   156→            return p;
   157→        }
   158→        // DCL
   159→        synchronized (this) {
   160→            p = provider;
   161→            if (p != null) {
   162→                return p;
   163→            }
   164→            if (!shouldLoad()) {
   165→                return null;
   166→            }
   167→
   168→            p = switch (provName) {
   169→                case "SUN", "sun.security.provider.Sun" ->
   170→                    new sun.security.provider.Sun();
   171→                case "SunRsaSign", "sun.security.rsa.SunRsaSign" ->
   172→                    new sun.security.rsa.SunRsaSign();
   173→                case "SunJCE", "com.sun.crypto.provider.SunJCE" ->
   174→                    new com.sun.crypto.provider.SunJCE();
   175→                case "SunJSSE" -> new sun.security.ssl.SunJSSE();
   176→                case "SunEC" -> new sun.security.ec.SunEC();
   177→                case "Apple", "apple.security.AppleProvider" -> {
   178→                    // Reflection is needed for compile time as the class
   179→                    // is not available for non-macosx systems
   180→                    Provider ap = null;
   181→                    try {
   182→                        Class<?> c = Class.forName(
   183→                            "apple.security.AppleProvider");
   184→                        if (Provider.class.isAssignableFrom(c)) {
   185→                            @SuppressWarnings("deprecation")
   186→                            Object tmp = c.newInstance();
   187→                            ap = (Provider) tmp;
   188→                        }
   189→                    } catch (Exception ex) {
   190→                        if (debug != null) {
   191→                            debug.println("Error loading provider Apple");
   192→                            ex.printStackTrace();
   193→                        }
   194→                    }
   195→                    yield ap;
   196→                }
   197→                default -> {
   198→                    if (isLoading) {
   199→                        // because this method is synchronized, this can only
   200→                        // happen if there is recursion.
   201→                        if (debug != null) {
   202→                            debug.println("Recursion loading provider: " + this);
   203→                            new Exception("Call trace").printStackTrace();
   204→                        }
   205→                        yield null;
   206→                    }
   207→                    try {
   208→                        isLoading = true;
   209→                        tries++;
   210→                        yield doLoadProvider();
   211→                    } finally {
   212→                        isLoading = false;
   213→                    }
   214→                }
   215→            };
   216→            provider = p;
   217→        }
   218→        return p;
   219→    }
   220→
   221→    /**
   222→     * Load and instantiate the Provider described by this class.
   223→     *
   224→     * @return null if the Provider could not be loaded
   225→     *
   226→     * @throws ProviderException if executing the Provider's constructor
   227→     * throws a ProviderException. All other Exceptions are ignored.
   228→     */
   229→    private Provider doLoadProvider() {
   230→        if (debug != null) {
   231→            debug.println("Loading provider " + ProviderConfig.this);
   232→        }
   233→        try {
   234→            Provider p = ProviderLoader.INSTANCE.load(provName);
   235→            if (p != null) {
   236→                if (hasArgument()) {
   237→                    p = p.configure(argument);
   238→                }
   239→                if (debug != null) {
   240→                    debug.println("Loaded provider " + p.getName());
   241→                }
   242→            } else {
   243→                if (debug != null) {
   244→                    debug.println("Error loading provider " +
   245→                        ProviderConfig.this);
   246→                }
   247→                disableLoad();
   248→            }
   249→            return p;
   250→        } catch (Exception e) {
   251→            if (e instanceof ProviderException) {
   252→                // pass up
   253→                throw e;
   254→            } else {
   255→                if (debug != null) {
   256→                    debug.println("Error loading provider " +
   257→                        ProviderConfig.this);
   258→                    e.printStackTrace();
   259→                }
   260→                disableLoad();
   261→                return null;
   262→            }
   263→        } catch (ExceptionInInitializerError err) {
   264→            // unable to initialize provider class
   265→            if (debug != null) {
   266→                debug.println("Error loading provider " + ProviderConfig.this);
   267→                err.printStackTrace();
   268→            }
   269→            disableLoad();
   270→            return null;
   271→        }
   272→    }
   273→
   274→    /**
   275→     * Perform property expansion of the provider value.
   276→     */
   277→    private static String expand(final String value) {
   278→        // shortcut if value does not contain any properties
   279→        if (value.contains("${") == false) {
   280→            return value;
   281→        }
   282→        try {
   283→            return PropertyExpander.expand(value);
   284→        } catch (GeneralSecurityException e) {
   285→            throw new ProviderException(e);
   286→        }
   287→    }
   288→
   289→    // Inner class for loading security providers listed in java.security file
   290→    private static final class ProviderLoader {
   291→        static final ProviderLoader INSTANCE = new ProviderLoader();
   292→
   293→        private final ServiceLoader<Provider> services;
   294→
   295→        private ProviderLoader() {
   296→            // VM should already been booted at this point, if not
   297→            // - Only providers in java.base should be loaded, don't use
   298→            //   ServiceLoader
   299→            // - ClassLoader.getSystemClassLoader() will throw InternalError
   300→            services = ServiceLoader.load(java.security.Provider.class,
   301→                                          ClassLoader.getSystemClassLoader());
   302→        }
   303→
   304→        /**
   305→         * Loads the provider with the specified class name.
   306→         *
   307→         * @param pn the name of the provider
   308→         * @return the Provider, or null if it cannot be found or loaded
   309→         * @throws ProviderException all other exceptions are ignored
   310→         */
   311→        public Provider load(String pn) {
   312→            if (debug != null) {
   313→                debug.println("Attempt to load " + pn + " using SL");
   314→            }
   315→            Iterator<Provider> iter = services.iterator();
   316→            while (iter.hasNext()) {
   317→                try {
   318→                    Provider p = iter.next();
   319→                    String pName = p.getName();
   320→                    if (debug != null) {
   321→                        debug.println("Found SL Provider named " + pName);
   322→                    }
   323→                    if (pName.equals(pn)) {
   324→                        return p;
   325→                    }
   326→                } catch (ServiceConfigurationError |
   327→                         InvalidParameterException ex) {
   328→                    // if provider loading failed
   329→                    // log it and move on to next provider
   330→                    if (debug != null) {
   331→                        debug.println("Encountered " + ex +
   332→                            " while iterating through SL, ignore and move on");
   333→                            ex.printStackTrace();
   334→                    }
   335→                }
   336→            }
   337→            // No success with ServiceLoader. Try loading provider the legacy,
   338→            // i.e. pre-module, way via reflection
   339→            try {
   340→                return legacyLoad(pn);
   341→            } catch (ProviderException pe) {
   342→                // pass through
   343→                throw pe;
   344→            } catch (Exception ex) {
   345→                // logged and ignored
   346→                if (debug != null) {
   347→                    debug.println("Encountered " + ex +
   348→                        " during legacy load of " + pn);
   349→                        ex.printStackTrace();
   350→                }
   351→                return null;
   352→            }
   353→        }
   354→
   355→        @SuppressWarnings("deprecation") // Class.newInstance
   356→        private Provider legacyLoad(String classname) {
   357→
   358→            if (debug != null) {
   359→                debug.println("Loading legacy provider: " + classname);
   360→            }
   361→
   362→            try {
   363→                Class<?> provClass =
   364→                    ClassLoader.getSystemClassLoader().loadClass(classname);
   365→
   366→                // only continue if the specified class extends Provider
   367→                if (!Provider.class.isAssignableFrom(provClass)) {
   368→                    if (debug != null) {
   369→                        debug.println(classname + " is not a provider");
   370→                    }
   371→                    return null;
   372→                }
   373→
   374→                return (Provider) provClass.newInstance();
   375→            } catch (Exception e) {
   376→                Throwable t;
   377→                if (e instanceof InvocationTargetException) {
   378→                    t = e.getCause();
   379→                } else {
   380→                    t = e;
   381→                }
   382→                if (debug != null) {
   383→                    debug.println("Error loading legacy provider " + classname);
   384→                    t.printStackTrace();
   385→                }
   386→                // provider indicates fatal error, pass through exception
   387→                if (t instanceof ProviderException) {
   388→                    throw (ProviderException) t;
   389→                }
   390→                return null;
   391→            } catch (ExceptionInInitializerError | NoClassDefFoundError err) {
   392→                // unable to access/initialize provider class
   393→                if (debug != null) {
   394→                    debug.println("Error loading legacy provider " + classname);
   395→                    err.printStackTrace();
   396→                }
   397→                return null;
   398→            }
   399→        }
   400→    }
   401→}
